class TestBroadcastPriorCost:
    def test_statusline_broadcast_includes_prior_cost(self, client, db) -> None:
        run_async(_seed_session(db, session_id="s1"))
        midnight = local_midnight_epoch()
        run_async(
            _seed_statusline(
                db, session_id="s1", received_at=midnight - 100, cost_usd=6.0
            )
        )

        payload = {
            "session_id": "s1",
            "cost": {"total_cost_usd": 8.5},
            "model": {"display_name": "Opus"},
        }
        with patch("agentpulse.events.manager.broadcast") as mock_bc:
            client.post("/statusline/claude", json=payload)

        updates = [
            c.args[0]
            for c in mock_bc.call_args_list
            if c.args[0]["type"] == "statusline_update"
        ]
        assert len(updates) == 1
        assert updates[0]["cost_usd"] == 8.5
        assert updates[0]["prior_cost_usd"] == 6.0

    def test_statusline_broadcast_zero_when_no_prior(self, client, db) -> None:
        payload = {
            "session_id": "fresh",
            "cost": {"total_cost_usd": 2.0},
            "model": {"display_name": "Sonnet"},
        }
        with patch("agentpulse.events.manager.broadcast") as mock_bc:
            client.post("/statusline/claude", json=payload)

        updates = [
            c.args[0]
            for c in mock_bc.call_args_list
            if c.args[0]["type"] == "statusline_update"
        ]
        assert updates[0]["prior_cost_usd"] == 0.0
